import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void singlePair() {
        int[][] result = new Solution().allPairs(new int[]{2, 7, 11, 15}, 9);
        assertArrayEquals(new int[][]{{0, 1}}, result);
    }

    @Test
    void multiplePairsAllOnes() {
        int[][] result = new Solution().allPairs(new int[]{1, 1, 1, 1}, 2);
        assertArrayEquals(new int[][]{{0, 1}, {0, 2}, {0, 3}, {1, 2}, {1, 3}, {2, 3}}, result);
    }

    @Test
    void twoSeparatePairs() {
        int[][] result = new Solution().allPairs(new int[]{1, 5, 3, 7, 2}, 8);
        assertArrayEquals(new int[][]{{0, 3}, {1, 2}}, result);
    }

    @Test
    void noPairs() {
        int[][] result = new Solution().allPairs(new int[]{1, 2, 3}, 100);
        assertArrayEquals(new int[][]{}, result);
    }
}
